class Solution {
public:
    bool isValidSerialization(string preorder) {
        int slots = 1;
        string cur;
        for (char c : preorder + ',') {
            if (c == ',') {
                slots--;
                if (slots < 0) return false;
                if (cur != "#") slots += 2;
                cur.clear();
            } else cur.push_back(c);
        }
        return slots == 0;
    }
};

